Что будет выведено при выполнении кода C#? Выберите ВСЕ правильные варианты:

class Animal { public virtual void Say() { Console.WriteLine("..."); } }
class Dog : Animal { public override void Say() { Console.WriteLine("Гав"); } }
class Cat : Animal { public override void Say() { Console.WriteLine("Мяу"); } }
Animal[] animals = { new Dog(), new Cat() };
foreach (Animal a in animals) a.Say();
